// 'http' is pre-imported via the node's libs config (module: http, var: http)
var token = msg.haToken;

var today = new Date();
var yyyy  = today.getFullYear();
var mm    = String(today.getMonth() + 1).padStart(2, '0');
var dd    = String(today.getDate()).padStart(2, '0');
var start = yyyy + '-' + mm + '-' + dd + 'T00:00:00';
var end   = yyyy + '-' + mm + '-' + dd + 'T23:59:59';

var calendars = {
    family:       'calendar.family',
    school:       'calendar.school',
    izzy:         'calendar.izzy',
    gavin:        'calendar.gavin',
    eric:         'calendar.eric',
    flavia:       'calendar.flavia',
    birthdays:    'calendar.birthdays',
    izzy_chores:  'calendar.izzy_choreops_calendar',
    gavin_chores: 'calendar.gavin_choreops_calendar'
};

function fetchCal(key, entityId) {
    return new Promise(function(resolve) {
        var path = '/api/calendars/' + entityId
                 + '?start=' + encodeURIComponent(start)
                 + '&end='   + encodeURIComponent(end);
        var opts = {
            hostname: '192.168.1.101',
            port:     8123,
            path:     path,
            method:   'GET',
            headers:  { 'Authorization': 'Bearer ' + token }
        };
        var req = http.request(opts, function(res) {
            var body = '';
            res.on('data', function(chunk) { body += chunk; });
            res.on('end', function() {
                try { resolve({ key: key, events: JSON.parse(body) }); }
                catch(e) { resolve({ key: key, events: [] }); }
            });
        });
        req.on('error', function() { resolve({ key: key, events: [] }); });
        req.end();
    });
}

var fetches = Object.keys(calendars).map(function(key) {
    return fetchCal(key, calendars[key]);
});

return Promise.all(fetches).then(function(results) {
    msg.calendarData = {};
    results.forEach(function(r) { msg.calendarData[r.key] = r.events; });
    return msg;
});

