const history = msg.payload;
let lastActiveTimestamp = 0;
let foundActive = false;


for (let i = history.length - 1; i >= 0; i --) {
    const entity = history[i];

    const attrs = entity.attributes;
    const isHvacActive = (attrs.hvac_action && attrs.hvac_action !== "idle");
    const isFanActive = (attrs.fan_mode && attrs.fan_mode !== "Auto low");

    if (isHvacActive || isFanActive) {
        lastActiveTimestamp = new Date(entity.last_updated).getTime();
        foundActive = true;
        break;
    }
}

if (!foundActive) {
    msg.reason = "No activity detected in the history buffer.";
    msg.topic = "run"
    return msg;
}

const now = new Date().getTime();
const diffMs = now - lastActiveTimestamp;
const diffMins = Math.floor((diffMs / 1000) / 60);

